static void test_blob_empty (void) {
  hb_blob_t *blob;
  const char *data;
  char *data_writable;
  unsigned int len;
  blob = hb_blob_get_empty ();
  g_assert (blob == hb_blob_get_empty ());
  len = hb_blob_get_length (blob);
  g_assert_cmpint (len, ==, 0);
  data = hb_blob_get_data (blob, NULL);
  g_assert (data == NULL);
}

static void test_buffer_allocation (fixture_t *fixture, gconstpointer user_data) {
  hb_buffer_t *b = fixture->buffer;
  g_assert_cmpint (hb_buffer_get_length (b), ==, 0);
  hb_buffer_add_utf8 (b, "a", 1, 0, 1);
  g_assert_cmpint (hb_buffer_get_length (b), ==, 1);
}

static void test_font_create (void) {
  hb_face_t *face = hb_face_create (hb_blob_get_empty (), 0);
  hb_font_t *font = hb_font_create (face);
  g_assert (font);
  hb_font_destroy (font);
  hb_face_destroy (face);
}
